INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027ec0e3c98b0941765c51', '服务超温暖，宾至如归，健身房环境一流，游泳池超好，早餐丰富多彩，非常可口，中式和西式早餐并存，还有地域特色', '["https://dimg04.c-ctrip.com/images/0237112000cckawhe23BD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000cckel8y93F8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235z12000cck9wry0F37_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-07', '花园双床房', '双床房', '家庭亲子', 53, 0, 1, 7, '["公共设施","餐饮设施","整体满意度"]'::jsonb, '公共设施', '餐饮设施', '整体满意度'),
('68027ec0e3c98b0941765c52', '第二次选择花园酒店，工作人员服务态度好，酒店还送我们早餐卷，在楼顶用餐，把整个城市景色收入眼帘，太棒了??', '["https://dimg04.c-ctrip.com/images/0202j12000cd1gtgh6F18_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0235s12000cd1g658F538_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233n12000cd1g2mvDEBA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234112000cd1ef7p4C2A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-09', '花园双床房', '双床房', '情侣出游', 53, 0, 5, 7, '["前台服务","餐饮设施","景观/朝向"]'::jsonb, '前台服务', '餐饮设施', '景观/朝向'),
('68027ec0e3c98b0941765c53', '非常满意 前台接待的工作人员都很好 有耐心 声音适中 服务人员都很有素质 配套设施卫生环境服务都很赞 不愧是老牌五星级酒店 白金五星的含金量真不错', '["https://dimg04.c-ctrip.com/images/0237012000c3ftnsg5E45_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l12000c3fm3qqA996_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000c3fszwqA0D2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-09', '城央绿意大床房', '大床房', '情侣出游', 73, 0, 2, 7, '["前台服务","整体满意度","卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况'),
('68027ec0e3c98b0941765c54', '非常惊喜的一次体验，中国唯三的白金五星级酒店。不同于其他国际品牌的统一性，这家酒店保留了历史的底蕴 民族品牌的特色和与时俱进的设施。前台Betty和迎宾非常细心，首次入住帮忙升级了房型。四点惊喜 ①花园绿化非常好 一看就是用心打理的成果，很出片 锦鲤非常漂亮②锦鲤酒吧 乐队水准极高 ，感染力强 本来是等外卖找地方坐坐，但代入感太强一直听到 外卖凉了③酒店博物馆推荐，对中国酒店业发展史有了了解 更被花园酒店的企业文化感染 ④酒店很国际化 推荐荔湾园 598双人套餐 极其丰富', '["https://dimg04.c-ctrip.com/images/0231y12000dlsge1dEDF4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w12000dlsfxir7EED_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232c12000dlsfm94EEEC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-06', '花园大床房', '大床房', '商务出差', 238, 0, 21, 9, '["整体满意度","前台服务","公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施'),
('68027ec0e3c98b0941765c55', '老牌豪华酒店！服务好！干净卫生！每次来广州出差，都会选择花园酒店！很挑剔床品枕头的，也可以安心睡！对面网红餐厅吃饭也很不错！', '["https://dimg04.c-ctrip.com/images/0233p12000c7f43l299E0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000c7f41vm13A4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-21', '花园双床房', '双床房', '商务出差', 62, 0, 14, 7, '["整体满意度","卫生状况","房间设施"]'::jsonb, '整体满意度', '卫生状况', '房间设施'),
('68027ecbe3c98b0941765c56', '第二次入住了，处处彰显细节，氛围很好。
Bobo. Y服务很好，很热情帮忙打印照片，连后花园的鱼儿都好热请。', '["https://dimg04.c-ctrip.com/images/0235812000cbqpjs87421_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234112000cbqntbi55DE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000cbqovt0753C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231q12000cbqlvf518F8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000cbqn5f01863_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-04', '花园双床房', '双床房', '家庭亲子', 54, 0, 11, 6, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027ecbe3c98b0941765c57', '花园酒店的服务，可以用润物细无声来描述。貌似没看到很多服务员，可服务一直在线。特别喜欢他们的荔湾亭餐厅，特色的老广州装修，老广州早茶是第一次住酒店就喜欢上了。退房的时候，小姐姐送上的洗漱旅行装手信，也很赞！', '["https://dimg04.c-ctrip.com/images/0233412000btsjjju7847_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234a12000btscjzgEC1D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-04', '花园大床房', '大床房', '家庭亲子', 103, 0, 2, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027ecbe3c98b0941765c58', '广州花园酒店是国内的白金五星级酒店。酒店有自己的博物馆、瀑布花园、26个景点等你来解锁。
房间环境不错，床品很好。
早饭有鲤鱼池和瀑布酒吧2个地方，来这里的外国人很多所以早餐有中、西、日三种，餐食品种繁多。
酒店服务员很多，特别要感谢前台Gillian，得知我们要去白云山想延迟退房，非常热心的帮我们办理了手续。
酒店出门就是5号线淘金站，去哪里都非常方便。', '["https://dimg04.c-ctrip.com/images/0236412000cxxtbe2D00C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232a12000cxxqynkA6CC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234112000cxy8sazD71F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000cxy691i0ED3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000cxy5qrh43E8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000cxxv7xx6534_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235012000cxy0zhl3253_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000cxy8ch2390C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234d12000cxy72i674B3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-15', '花园双床房', '双床房', '家庭亲子', 179, 0, 62, 9, '["交通便利性","前台服务","餐饮设施"]'::jsonb, '交通便利性', '前台服务', '餐饮设施'),
('68027ecbe3c98b0941765c59', '入住了期待已久的花园酒店，大堂环境大气奢华，有一个后花园可以散步，有博物馆可以参观，有画展可看，有康养中心可以桑拿休闲，很有文化底蕴，也非常适合亲子游入住。听说酒店有好几个米其林餐厅，但只来得及吃了一个瀑布餐厅早餐，种类还算丰富，味道一般，好在瀑布景观不错。作为老式酒店，房间维持的还算不错，干净整洁。花园酒店自带一种优雅的贵族气质，它不像一般网红五星酒店有种暴发户的气质，它注重自己的文化气质，是时间沉淀过的地方。入住还有送宝格丽的护肤品，非常nice。还有就是好多老外啊，这里简直给我一种在国外度假的感觉哈哈，另外附近的利苑酒家很好吃', '["https://dimg04.c-ctrip.com/images/0234l12000bslcdwx599D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000bslfnvc3892_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235a12000bsld9zy9B6E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234412000bsl9hka2B8D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000bslgtuhC8DB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000bsli5dj9CF6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g12000bslf6ujAAC8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233v12000bslbls68095_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-31', '花园双床房', '双床房', '朋友出游', 269, 1, 2, 9, '["整体满意度","公共设施","餐饮设施"]'::jsonb, '整体满意度', '公共设施', '餐饮设施'),
('68027ecbe3c98b0941765c5a', '服务很好 环境很好 瀑布餐厅很出片 房间很干净整洁 生日还给我们送了甜点和蛋糕 是个难忘的生日 会和朋友推荐推荐～', '["https://dimg04.c-ctrip.com/images/0232412000cbbyoa2830D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231p12000cbbykujC0AA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230x12000cbc41nz727D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-03', '红棉双床套房', '套房', '朋友出游', 57, 0, 4, 7, '["整体满意度","客房服务","卫生状况"]'::jsonb, '整体满意度', '客房服务', '卫生状况'),
('68027ecbe3c98b0941765c5b', '有底蕴的酒店，服务非常周到，期待再次入住！', '["https://dimg04.c-ctrip.com/images/0235c12000cptynir1635_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235512000cpu7cys1279_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000cptynitC14D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233u12000cptxeec73AE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-11', '花园双床房', '双床房', '情侣出游', 21, 0, 13, 4, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027ecbe3c98b0941765c5c', '房间有异味，但是作为老牌五星环境和服务还是非常在线的。设施有点旧了希望可以翻新一下，下次还是很期待入住花园酒店的。', '["https://dimg04.c-ctrip.com/images/0230r12000cakwbj311F7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-09-30', '花园双床房', '双床房', '朋友出游', 57, 0, 24, 7, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68027ecbe3c98b0941765c5d', '出发前纠结了好久，担心酒店会太陈旧，
到了后意识到自己多虑了～
从check in遇到Betty就预示着此次入住体验极佳，Betty见我带着老人和小孩，贴心滴给我们两间房做了升级，粤韵的硬件很不错，自带小厅让活动范围大大增加，舒适度指数大涨，大床房还有?????泡澡，总体来说这次入住是很Nice的体验～下次来广州还会选择花园酒店。
要说欠缺的点，那就是近期泳池在升级改造，不在开放期，小朋友有点失望。', '["https://dimg04.c-ctrip.com/images/0235w12000bqyaxaa7830_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234a12000bqy74e2AAD3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232612000bqyl3vzCDB7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233n12000bqy91g519AD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000bqyjdwa05A9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230l12000bqylbcpA5C7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-26', '花园双床房', '双床房', '家庭亲子', 201, 1, 2, 9, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('68027ecbe3c98b0941765c5e', '虽然是几十年的酒店 但维护真的极好 工作人员服务完全超五星 办理入住的小哥带着两个可爱的兔牙笑容灿烂 退房的小姐姐专业速度 还赠送了小礼物 …
必须点赞??????', '["https://dimg04.c-ctrip.com/images/0232g12000c3hljs51080_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232212000c3hlmmb8D59_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000c3hln7dCBCE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235u12000c3hlidfB96C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-09', '花园大床房', '大床房', '家庭亲子', 82, 0, 5, 8, '["前台服务","退房/入住效率","整体满意度"]'::jsonb, '前台服务', '退房/入住效率', '整体满意度'),
('68027ecbe3c98b0941765c5f', '38年来一直都是中国酒店行业的天花板，区别于瑰丽和四季丽思卡尔顿瑞吉W的享用', '["https://dimg04.c-ctrip.com/images/0234512000chrm6vwF290_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-01', '花园大床房', '大床房', '独自旅行', 38, 0, 32, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027ed8e3c98b0941765c60', '管理规范，设施一流，环境优雅！', '["https://dimg04.c-ctrip.com/images/0230i12000cr8uuoe9AE9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000cr8w1od3343_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u12000cr8wjimFF94_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232h12000cr8vqbl3509_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-18', '城央绿意大床房', '大床房', '商务出差', 15, 0, 8, 4, '["整体满意度","公共设施","卫生状况"]'::jsonb, '整体满意度', '公共设施', '卫生状况'),
('68027ed8e3c98b0941765c61', '酒店环境好，但是房间比较小，服务还可以，就是我看到携程有帮我匹配成岭客汇金卡会员，可是没有看到欢迎水果、行政酒廊使用等等，快速退房就更是没有了，退房碰到系统问题，我抱着小孩在那里排队等，也没看到服务员来告诉我，还是我主动问的。PS：早餐有赠送给我，就是菜品不够丰富，说是一楼二楼有中西餐区别，其实差不多！', '["https://dimg04.c-ctrip.com/images/0233312000bqn713c1C0A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232112000bqn3huz2F8C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000bqn16cq5987_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000bqnaz505CDD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235c12000bqmy6zq2EB4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000bqn82x4BC61_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237412000bqnbnb12E55_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2023-07-25', '花园双床房', '双床房', '家庭亲子', 152, 1, 3, 7, '["前台服务","退房/入住效率","餐饮设施"]'::jsonb, '前台服务', '退房/入住效率', '餐饮设施'),
('68027ed8e3c98b0941765c62', '必须满分！作为老牌酒店，服务真的好，从下车至前台，各工作人员都让人感觉宾至如归。房间配套设施完善，维护得很好。值得推荐入住！', '["https://dimg04.c-ctrip.com/images/0230x12000c7h7fl9E3EE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236e12000c7h8astF760_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000c7ha6eb017B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-22', '红棉大床套房', '套房', '朋友出游', 62, 0, 16, 7, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68027ed8e3c98b0941765c63', '环境非常好，不愧是花园酒店，后花园一定要参观一下，有瀑布和小桥流水还有各种花草。红棉大床房面积很大，有个厅，加了床，三个人住很舒适。唯一不足是服务，因为到达时间已是半夜，早上提前致电前台说了务必把床提前加好，结果半夜一点到了依然没加，坐等加完才能休息，此刻的心情谁懂。', '["https://dimg04.c-ctrip.com/images/0236n12000br1s7wkFAA8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236o12000br1kn2cC852_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000br1n6bdB320_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236c12000br1p57g7F46_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232f12000br1l2xy485F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000br1l7443DBE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000br1owma54B5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-07-26', '红棉大床套房', '套房', '家庭亲子', 134, 0, 2, 8, '["整体满意度","房间设施","前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务'),
('68027ed8e3c98b0941765c64', '不愧是白金五星级酒店，入住感觉非常满意，第一要表扬的是前台的吴经理，没有见到人，提前一天就直接打电话跟她商量，因为带了孩子能不能房间给调整成床铺比较大的，结果她真的帮忙给协调升级成双床套房；第二个要表扬的是前台的viria，入住效率快，办事认真体贴，给孩子申请了一个儿童餐，虽然孩子不吃什么东西，但是享受到了酒店的温暖！希望酒店能继续保持这种人性化的关怀！第三个要表扬的就是酒店的客房服务，需要补充饮用水或者是房间用品时响应速度非常快，客房的清洁阿姨（是东北过来的阿姨）态度也非常好，做事情速度快，整理得很清楚！你是个就要表扬早餐瀑布餐厅的服务员，真的真的很棒，态度温和有礼，服务积极！
     特别特别要提一点的是，花园酒店的位置太好了，一出门右转就是淘金口地铁站，去哪儿都非常方便，因为带的很多行李，所以非常庆幸选择的花园酒店
      整体这次入住的感觉就是酒店服务人员都是高素质的，路上碰到都会打招呼，餐饮服务也都很认真细致！', '["https://dimg04.c-ctrip.com/images/0233o12000c774dtuEE59_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230m12000c774f0x6E14_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232c12000c774g6m667E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236w12000c774i3q0D80_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233a12000c774khi24B2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236d12000c774knp1ABB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-21', '红棉大床套房', '套房', '家庭亲子', 419, 0, 9, 9, '["前台服务","客房服务","交通便利性"]'::jsonb, '前台服务', '客房服务', '交通便利性'),
('68027ed8e3c98b0941765c65', '早餐果子里有虫子.房间一开始很吵（因为楼下装修）然后给我从很吵的房间换到了一个空调一直出臭气的房间.', '["https://dimg04.c-ctrip.com/images/0204712000cdfwxp26C28_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0236712000cdfrbow5199_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1, 1, '2023-10-11', '花园双床房', '双床房', '朋友出游', 50, 0, 1, 7, '["餐饮设施","安静程度","房间设施"]'::jsonb, '餐饮设施', '安静程度', '房间设施'),
('68027ed8e3c98b0941765c66', '提前和酒店沟通了是来过生日，前台的joe和ann帮忙升级了粤韵房型，还赠送了单人的行政礼遇，房间是19年装修的，比较新。行政酒廊的Carrie很热情，食物出品也不错。晚上回到房间发现酒店还赠送了生日蛋糕和点心。
美中不足是第二天在桃园馆餐厅使用了500签账额，口味一般，肉筋没剃除，勺子没洗干净，不合米其林的出品。', '["https://dimg04.c-ctrip.com/images/0232f12000c4rsq1eEAF1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236312000c4rolqx00A7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237412000c4rjkotBF72_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233r12000c4riizgE991_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236s12000c4rykywCF90_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234a12000c4rn8zdB04E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234l12000c4rvspoEE43_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000c4rsmtq131F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233q12000c4roi8sFFB9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-14', '红棉大床套房', '套房', '独自旅行', 157, 0, 2, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027ed8e3c98b0941765c67', '每一个工作人员服务态度都很好，非常满意的一次住宿体验。酒店配备了不少设施，小朋友也能在酒店晚上一会儿。', '["https://dimg04.c-ctrip.com/images/0234c12000cc4k1w3B64B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000cc4jivd5AE6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231g12000cc4jpgv0FBB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-05', '花园双床房', '双床房', '家庭亲子', 51, 0, 6, 5, '["前台服务","整体满意度","公共设施"]'::jsonb, '前台服务', '整体满意度', '公共设施'),
('68027ed8e3c98b0941765c68', '老酒店有品味，值得体验', '["https://dimg04.c-ctrip.com/images/0234a12000d16c1hhD495_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000d16c2nv37A5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-25', '红棉大床套房', '套房', '朋友出游', 11, 0, 48, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027ed8e3c98b0941765c69', '我们是岭南汇的会员，多次去花园酒店了，一次比一次惊喜，房间升级了，非常舒适，我们代表广州15-19号去??庆打省锦标游泳比赛，在??庆喜来登住了两晚，这酒店不想评价，但没下次，然后去了亚朵住了一晚，亚朵的排污管老有臭气攻进房间这缺点一直都有，所以不是没选择是绝不住这酒店了，漂了5天刚回到家睡了一晚，又说小区停电，刚好又是我女儿12岁生日，我们立刻马上就飞奔去了花园酒店开房了，真的是家里的酒店最好，一间四十年的全中国唯一三间中国自己开的涉外酒店，服务真的细致，见到我们是国际家庭，马上有外国前台来接待，当知道我们是带孩子来过生日，还送了我们一盘非常新鲜的欢迎水果给孩子，自助早餐也非常好，新鲜，中西合璧，非常好吃，而且招待非常好，有服务员带位，不会像喜来登吃个早餐会有个男人跑来说要和你拼桌，在花园酒店你会感受到真正五星级酒店的服务和礼仪，还有真正的尊重及被酒店的欢迎，花园酒店的确是值得去渡假首选的酒店，酒店内的博物馆也得一去，会让你重新认识广州及中国到全世界的酒店发展历史，值得带孩子一起去参观！', '["https://dimg04.c-ctrip.com/images/0230n12000bpopo926242_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000bpopjdn00A7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000bpokopyBA50_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000bpoq4sp8E47_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-21', '花园双床房', '双床房', '家庭亲子', 451, 0, 12, 9, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68027ee3e3c98b0941765c6a', '酒店非常干净，设施也都很新，前台小姐姐viria和ariel超级nice、有耐心，笑容甜美，服务周到！好评好评！以后会再来的！z
对了，早餐很好吃哦！！', '["https://dimg04.c-ctrip.com/images/0231y12000bze47kc1A59_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235412000bze5isk4242_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-23', '花园大床房', '大床房', '独自旅行', 76, 0, 4, 8, '["卫生状况","前台服务","餐饮设施"]'::jsonb, '卫生状况', '前台服务', '餐饮设施'),
('68027ee3e3c98b0941765c6b', '第一次认真评价：房间小，设施陈旧，体验感差，瀑布花园还不错，孩子喂喂鱼玩儿了一会儿，瀑布餐厅早餐一般，还需要排队，而且服务员业务不熟练，总结一下就是：如果白天出去玩儿，晚上回去只住一下酒店的，那不推荐住这儿，因为房间小，布局也不合理。如果白天不出去，只在酒店休息的话，也不推荐，因为房间里待着又潮又暗。住了两天，非常不舒服，这酒店唯一的优点就是大堂好看，瀑布花园还不错，虚有其表，住的房间是真不行。', '["https://dimg04.c-ctrip.com/images/0232x12000bqhucoa43E0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234g12000bqhwmcj3DAE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000bqhtapz333D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.5, 2, '2023-07-24', '花园双床房', '双床房', '家庭亲子', 199, 6, 4, 9, '["房间设施","整体满意度","卫生状况"]'::jsonb, '房间设施', '整体满意度', '卫生状况'),
('68027ee3e3c98b0941765c6c', '被种草，特意带孩子来打卡花园酒店，不愧是白金五星酒店的，获奖无数，见证了很多很有意义的历史时刻。不仅有非常硬核的硬件，软性服务也让人如沐春风！细节非常到位，进门就碰到小姐姐演奏，每层楼都有鲜花点缀 造型各异等等 真正让人感到宾至如归！尤其表扬经理Tina小姐姐，温柔美貌 彬彬有礼，遇到问题很快就帮我解决了，非常圆满！祝花园酒店越来越好', '["https://dimg04.c-ctrip.com/images/0232u12000cz19cn8CD6C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b12000cz18fss767E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232c12000cz19ez7980F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233q12000cz19cna6001_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233712000cz18fsu5BC3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233812000cz19ez9E0F0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m12000cz19cncC81B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000cz18fswF8EF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234412000cz19ezbE352_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-19', '花园双床房', '双床房', '家庭亲子', 168, 0, 2, 9, '["整体满意度","前台服务","公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施'),
('68027ee3e3c98b0941765c6d', '住了十几天，感觉很舒服。空调干湿度控制的很好，不会像一些酒店太干燥。床褥松软温暖，很适合睡眠。早餐很棒。', '["https://dimg04.c-ctrip.com/images/0236h12000ccptfgr042D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-08', '花园双床房', '双床房', '商务出差', 52, 0, 4, 7, '["房间设施","餐饮设施","整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度'),
('68027ee3e3c98b0941765c6e', '一开始选择看了其他酒店，最后还是选了这家，环境舒适，服务也不错，很不错的一次体验，下次还会介绍朋友！', '["https://dimg04.c-ctrip.com/images/0230412000ccabub86914_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233712000cca7xrjC43C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000cca9mgs8DB3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000ccafcleBC6C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000ccaczrg1D21_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233k12000ccacew92644_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-06', '花园双床房', '双床房', '家庭亲子', 50, 0, 2, 5, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027ee3e3c98b0941765c6f', '入住时前台的人员服务很好，风景很好，设施设备也不错，床品挺舒适的，房间服务员也很用心，还准备了甜点和问候的卡片，总体感觉很不错。', '["https://dimg04.c-ctrip.com/images/0232w12000c4edjny068E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232m12000c4ednkuC255_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w12000c4edqg0F5C6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236712000c4edrro1044_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-13', '花园大床房', '大床房', '商务出差', 64, 0, 1, 7, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('68027ee3e3c98b0941765c70', '广州带娃办事，只停留一天的情况下，庆幸订了花园酒店。
这是一所名副其实的酒店，酒店一楼真真正正的有个很大的花园，一步一景，也是中国三家白金五星的唯一民族品牌，从今天上个世纪80年代开始规划，面积庞大、包罗万象，我带娃在酒店里面玩一天都不带重样的。
酒店前台服务很优秀，遇到Billy为我们办理入住，给宝贝提供了精美的小玩具，也帮忙升级房间到比较新的户型，行李也帮忙送到房间，给宝贝加的小床刚刚好可以放在我们的大床旁边，一直说“交给我吧”，很给力！
酒店自带瀑布景观餐厅，可以用早餐，因为我单独带娃吃饭，从很里面的位置又换了一个更方便的位子，服务人员也很配合。（隐藏福利，30楼有一个旋转餐厅也可以用早餐，只有上午开放到12点，入住的大家可以来看看）。
酒店的四楼还有博物馆，带宝贝逛了一圈也不会接的腻，还买了纪念品。（隐藏福利，酒店的户外泳池变有个儿童乐园，一般都是公寓常住客带娃去玩很少有人知道）。', '["https://dimg04.c-ctrip.com/images/0232912000ccr3h4q2D87_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000ccr4ha319F2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233e12000ccqzk0c3EB9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000ccr4ha79FE3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d12000ccr39ct0588_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g12000ccr25744FB1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000ccqwlvpBA38_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000ccr4vk394B2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000ccqzk0m2A71_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-08', '红棉大床套房', '套房', '家庭亲子', 400, 0, 2, 9, '["前台服务","公共设施","餐饮设施"]'::jsonb, '前台服务', '公共设施', '餐饮设施'),
('68027ee3e3c98b0941765c71', '酒店地理位置很好，出行方便，大厅工作人员很有礼貌，我带着老人和孩子出行，一下车小哥就帮忙拿行李，帮我寄存。我想去的地方工作人员又耐心告诉我怎么走，虽说房间面积不大，但已经很好了。很满意。', '["https://dimg04.c-ctrip.com/images/0235i12000bryaofuC266_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000bry8o1a6540_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-29', '城央绿意双床房', '双床房', '家庭亲子', 93, 1, 8, 8, '["交通便利性","前台服务","整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度'),
('68027ee3e3c98b0941765c72', '入住花园酒店、前台富丽堂皇、博物馆和后花园都很不错??歺食精美。这次美中不足我们预定好的房间没有了、前台小哥只是降标安排了一间，后来还是前台许诗玮经理又调剂了一间，第二天还升级了房间送了水果和蛋糕??，许经理楼上楼下跑了好几趟送房卡拿行李、耐心解释道谦，给我们很好的补偿，为许经理的热情服务和敬业精神点赞。房间的保洁和歺厅服务也很赞。谢谢花园酒店！', '["https://dimg04.c-ctrip.com/images/0234w12000cspi49254EC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000csp8c8c1D33_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000cspu20p717C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-25', '花园双床房', '双床房', '情侣出游', 174, 0, 23, 9, '["前台服务","整体满意度","客房服务"]'::jsonb, '前台服务', '整体满意度', '客房服务'),
('68027ee3e3c98b0941765c73', '酒店的公共区域无可挑剔，客房内部设施与卫生也做得很好，贴心的前台Vivia还给小朋友赠送了自助早餐。', '["https://dimg04.c-ctrip.com/images/0233d12000cbyqp2107FA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000cbyvdkd2AB0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000cbyp44pBC9F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-05', '花园双床房', '双床房', '家庭亲子', 50, 0, 2, 7, '["公共设施","房间设施","前台服务"]'::jsonb, '公共设施', '房间设施', '前台服务'),
('68027ef2e3c98b0941765c74', '白金五星名不虚传，38年的老牌酒店，19年新装修，比现代化的很多五星有文化内涵，后花园美景，服务一流，美食有几家米其林榜的，特别是入住时前台银小姐热情细致介绍，特意赞一个，订的红棉套房还给免费升级到雅韵套房', '["https://dimg04.c-ctrip.com/images/0233912000c5pw2me8769_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-16', '红棉双床套房', '套房', '其他', 103, 0, 65, 9, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68027ef2e3c98b0941765c75', '一家人出行住了几天，非常满意，酒店文化底蕴深厚，服务环境餐饮价格等各方面都是最好的，真的是流连忘返！', '["https://dimg04.c-ctrip.com/images/0230a12000cbj994b964F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000cbj9e8i87F4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235z12000cbj9pp4B6DE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-03', '花园双床房', '双床房', '家庭亲子', 50, 0, 1, 6, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('68027ef2e3c98b0941765c76', '入住当天送了一份精美的甜品蛋糕，来不及拍照被两娃给秒吃了。房间很大，酒店的环境不错，大门口就是淘金地铁站，对面就是友谊商场，广州酒家，去景点也都3-5公里内，很方便。', '["https://dimg04.c-ctrip.com/images/0236612000bvsjss66495_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-11', '红棉大床套房', '套房', '家庭亲子', 83, 0, 3, 8, '["交通便利性","周边配套","整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度'),
('68027ef2e3c98b0941765c77', '酒店设计一流，服务跟得上，餐饮一般，虽然有几家都是米其林推荐餐厅，但是味道远不如我们去的路边老字号。', '["https://dimg04.c-ctrip.com/images/0235712000cb1v08d8D1D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000cb1vbcb7A77_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-02', '花园双床房', '双床房', '家庭亲子', 50, 0, 3, 7, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('68027ef2e3c98b0941765c78', '酒店位置非常方便，在越秀区离地铁站很近，大堂环境非常有特色，早餐也很好，房间设施稍稍有点久远，不过服务还是不错的，总体来说体验感很好，有机会还会再来。', '["https://dimg04.c-ctrip.com/images/0234w12000c1355d128B5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230h12000c1355d77AAB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231d12000c1355da876F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000c134w5mB8DF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000c1355ddCBB7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233312000c134w5s8890_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-08-29', '花园大床房', '大床房', '家庭亲子', 75, 0, 75, 8, '["交通便利性","整体满意度","餐饮设施"]'::jsonb, '交通便利性', '整体满意度', '餐饮设施'),
('68027ef2e3c98b0941765c79', '整个花园酒店如其名，各种各样的花。大厅，餐厅，迎宾的服务人员都很nice。
环境优美，房间舒适，美食美景，心情舒畅。', '["https://dimg04.c-ctrip.com/images/0237012000c8fck7rE25C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000c8fjiqv8230_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f12000c8flmlt35D3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235j12000c8flael9B9D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-24', '红棉大床套房', '套房', '朋友出游', 58, 0, 3, 6, '["整体满意度","周边配套","前台服务"]'::jsonb, '整体满意度', '周边配套', '前台服务'),
('68027ef2e3c98b0941765c7a', '国庆亲子出游，很不错，地铁出来就是，很方便，干净卫生，早餐很丰富，中西文化餐厅，瀑布餐厅非常有特色！', '["https://dimg04.c-ctrip.com/images/0234412000cb3iv6y6322_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000cb3gi09CA79_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230712000cb3bb0n2AFA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233412000cb3dx9rFAE0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000cb3dx9t5CC9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000cb3fe173500_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235j12000cb3j89366A0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-02', '花园双床房', '双床房', '家庭亲子', 50, 0, 8, 7, '["交通便利性","餐饮设施","卫生状况"]'::jsonb, '交通便利性', '餐饮设施', '卫生状况'),
('68027ef2e3c98b0941765c7b', '硬件无可挑剔，软件有待提高！', '["https://dimg04.c-ctrip.com/images/0231z12000cq91ywu76E1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000cq938vc4ABB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000cq8v8cy9328_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232e12000cq8wdee33BB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000cq939aaF0FF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000cq90fqe67EE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236y12000cq8yppvEFA3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000cq8xdgqDE09_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-12-13', '红棉大床套房', '套房', '情侣出游', 14, 0, 28, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027ef2e3c98b0941765c7c', '花园酒店确实做得太到位了！早餐服务环境样样都没得说，实打实的舒服贴心。强烈建议去瀑布餐厅吃早饭，早上的慢时光看着瀑布镇的一天心情都变好～', '["https://dimg04.c-ctrip.com/images/0235912000c1jnboe2F4D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235a12000c1jn5h7F6AC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234g12000c1jn9xjC0F8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230512000c1jnd89D817_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236e12000c1jnd944F32_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-31', '红棉大床套房', '套房', '情侣出游', 68, 0, 6, 7, '["餐饮设施","整体满意度","景观/朝向"]'::jsonb, '餐饮设施', '整体满意度', '景观/朝向'),
('68027ef2e3c98b0941765c7d', '本次住宿非常愉快
果然是超白金的五星酒店

很幸运入住时候前台升级成了套间

环境：维护很好，37年的酒店，但是经常翻新，维护得很好

服务：无论是前台人员，电梯遇见的员工，退房的小钰态度都很好

饮食:   行政下午茶，早餐（荔湾亭和瀑布餐厅）都很好，出品精致，味道一流

下次来广州，还是会想住花园酒店', '["https://dimg04.c-ctrip.com/images/0230e12000c1rqyot14F0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w12000c1rrno34946_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000c1rulcs1758_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236j12000c1rq91a44F9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230l12000c1rtnip5E5D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234n12000c1rrr535161_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231412000c1s07qh1AC4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000c1rwwpiAF5B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-01', '花园双床房', '双床房', '家庭亲子', 153, 0, 19, 9, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68027efee3c98b0941765c7e', '广州五星级酒店性价比之王，住过多次了。位置得天独厚，卫生安全放心，服务专业，越来越好。早餐好吃，环境好。', '["https://dimg04.c-ctrip.com/images/0232x12000c90etu0E3B6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000c90dl0c767F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000c90a4pf538B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-26', '花园大床房', '大床房', '情侣出游', 52, 0, 21, 6, '["性价比","整体满意度","餐饮设施"]'::jsonb, '性价比', '整体满意度', '餐饮设施'),
('68027efee3c98b0941765c7f', '房间很小，但是有浴缸，就很挤。。
但是公共设施还行，毕竟是五星酒店。。

押金一直没退，刚刚打电话我问押金一般什么时候退？说是如果没别的费用当天就会退，反之隔天。
我说我没别的费用为什么都离店第三天了，还没退呢？她说前台同事会跟进的，然后不说话，我一脸懵逼。。我就说那现在是等他们再联系我？她才说让我等十分钟就会退回。。
我可以理解为工作人员忘了操作吗？如果我不打电话问是不是永远不退呢？
还有你们客服真的很不专业。不会和客人沟通。', '["https://dimg04.c-ctrip.com/images/0233312000bof8cw2E8E2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236112000bof7rzg11B3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.7, 2, '2023-07-17', '花园大床房', '大床房', '家庭亲子', 216, 3, 3, 8, '["前台服务","退房/入住效率","房间设施"]'::jsonb, '前台服务', '退房/入住效率', '房间设施'),
('68027efee3c98b0941765c80', '生日跟先生过来庆祝，整体很满意，办理入住速度也超快的，小哥个和小姐姐都服务很好，体验不错，下次会再过来。', '["https://dimg04.c-ctrip.com/images/0236q12000c8msnkvE6C0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233v12000c8mviooE683_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-25', '花园大床房', '大床房', '情侣出游', 52, 0, 5, 6, '["整体满意度","退房/入住效率","前台服务"]'::jsonb, '整体满意度', '退房/入住效率', '前台服务'),
('68027efee3c98b0941765c81', '老牌五星，相当不错??虽然入住排队，工作人员贴心准备了好好吃的曲奇饼??  市政施工下午房间会有点吵，工作人员帮忙换房，送了酒店可爱的羊羊公仔??  泳池和博物馆也都要赞一下，服务5星??值得再次入住^_^', '["https://dimg04.c-ctrip.com/images/0230s12000bo8c0qr6C20_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000bo8c0z40571_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000bo8c1y156A0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d12000bo8c1e47DFD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236d12000bo8bzdfA53F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-16', '红棉双床套房', '套房', '家庭亲子', 103, 0, 1, 8, '["整体满意度","前台服务","公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施'),
('68027efee3c98b0941765c82', '白金五星级酒店，环境优美大气，花园瀑布、锦鲤鱼池很美！服务专业到位，宾至如归！酒店美食不错，博物馆里学习了不好知识，是出差、旅行的首选酒店。五星好评??', '["https://dimg04.c-ctrip.com/images/0234t12000bykn4bm35CC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235412000byksrrw9516_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233x12000bykt5i39727_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000bykulwi7157_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-20', '花园双床房', '双床房', '家庭亲子', 76, 0, 4, 7, '["整体满意度","公共设施","餐饮设施"]'::jsonb, '整体满意度', '公共设施', '餐饮设施')
